css:
.loader {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
  width: 120px;
  height: 20px;
  transform: skewX(-45deg);
  background:linear-gradient(var(--loader-color, #f97316) 0 0) left -30px top 0/30px 20px no-repeat var(--loader-secondary-color, #facc15);
  animation: l3 1s infinite linear;
}
@keyframes l3 {100% {background-position: right -30px top 0}}
